  1463      /// Should only be used to implement 'Transform.concatenatedMatrix'
  1464      #[no_dynamic]
  1465      fn local_to_global_matrix_without_own_scroll_rect(self) -> Matrix {
  1466          let mut node = self.parent();
  1467          let mut matrix = self.base().matrix();
  1468          while let Some(display_object) = node {
  1469              // We want to transform to Stage-local coordinates,
  1470              // so do *not* apply the Stage's matrix
  1471              if display_object.as_stage().is_some() {
  1472                  break;
  1473              }
  1474              if let Some(rect) = display_object.scroll_rect() {
  1475                  matrix = Matrix::translate(-rect.x_min, -rect.y_min) * matrix;
  1476              }
  1477              matrix = display_object.base().matrix() * matrix;
  1478              node = display_object.parent();
  1479          }
  1480          matrix
  1481      }
