  1512      /// Converts the mouse position on the stage to a local position on this display object.
  1513      /// If the object has zero scale, then the stage `TWIPS_TO_PIXELS` matrix will be used.
  1514      /// This matches Flash's behavior for `mouseX`/`mouseY` on an object with zero scale.
  1515      #[no_dynamic]
  1516      fn local_mouse_position(self, context: &UpdateContext<'gc>) -> Point<Twips> {
  1517          let stage = context.stage;
  1518          let pixel_ratio = stage.view_matrix().a;
  1519          let virtual_to_device = Matrix::scale(pixel_ratio, pixel_ratio);
  1520
  1521          // Get mouse pos in global device pixels
  1522          let global_twips = *context.mouse_position;
  1523          let global_device_twips = virtual_to_device * global_twips;
  1524          let global_device_pixels = Matrix::TWIPS_TO_PIXELS * global_device_twips;
  1525
  1526          // Make transformation matrix
  1527          let local_twips_to_global_twips = self.local_to_global_matrix();
  1528          let twips_to_device_pixels = virtual_to_device * Matrix::TWIPS_TO_PIXELS;
  1529          let local_twips_to_global_device_pixels =
  1530              twips_to_device_pixels * local_twips_to_global_twips;
  1531          let global_device_pixels_to_local_twips = local_twips_to_global_device_pixels
  1532              .inverse()
  1533              .unwrap_or(Matrix::IDENTITY);
  1534
  1535          // Get local mouse position in twips
  1536          global_device_pixels_to_local_twips * global_device_pixels
  1537      }
