import re
import struct
import sys
import zlib
from pathlib import Path

repo = Path(sys.argv[1]) if len(sys.argv) > 1 else Path('/workspace/ruffle')
swf_path = Path(sys.argv[2]) if len(sys.argv) > 2 else Path('/tmp/ruffle_issue.swf')

