    nbits = data[pos] >> 3
    return pos + (5 + nbits * 4 + 7) // 8

def read_matrix(data, pos):
    bit = 0
    def getbits(n):
        nonlocal pos, bit
        value = 0
        for _ in range(n):
            value = (value << 1) | ((data[pos] >> (7 - bit)) & 1)
            bit += 1
            if bit == 8:
                bit = 0
                pos += 1
        return value
    if getbits(1):
        n = getbits(5); getbits(n); getbits(n)
    if getbits(1):
        n = getbits(5); getbits(n); getbits(n)
    n = getbits(5); getbits(n); getbits(n)
    if bit:
        pos += 1
    return pos

def read_cxform_with_alpha(data, pos):
    bit = 0
    def getbits(n):
        nonlocal pos, bit
        value = 0
        for _ in range(n):
            value = (value << 1) | ((data[pos] >> (7 - bit)) & 1)
            bit += 1
            if bit == 8:
                bit = 0
                pos += 1
        return value
    has_add = getbits(1)
    has_mult = getbits(1)
    n = getbits(4)
    if has_mult:
        for _ in range(4): getbits(n)
    if has_add:
        for _ in range(4): getbits(n)
    if bit:
        pos += 1
    return pos

def iter_tags(data, pos, end):
    while pos + 2 <= end:
        header = struct.unpack_from('<H', data, pos)[0]
        pos += 2
        code = header >> 6
        length = header & 0x3f
        if length == 0x3f:
            length = struct.unpack_from('<I', data, pos)[0]
            pos += 4
        body = data[pos:pos + length]
        pos += length
        yield code, body
        if code == TAG_END:
            break

def collect_swf_features(path):
    data = path.read_bytes()
    if data[:3] == b'CWS':
        data = data[:8] + zlib.decompress(data[8:])
